// A02 Normalize Telegram Input
// Универсальная нормализация Telegram update из Cloudflare Worker, n8n Webhook или Telegram Trigger.

function parseMaybeJson(value) {
  if (value === null || value === undefined) return {};
  if (typeof value !== 'string') return value;

  const s = value.trim();
  if (!s) return {};

  try {
    return JSON.parse(s);
  } catch (e) {
    return {};
  }
}

function unwrapIncoming(input) {
  let cur = input || {};

  // n8n Webhook часто кладёт payload в body.
  if (cur.body !== undefined) {
    cur = parseMaybeJson(cur.body);
  }

  // Иногда после прокси body может быть вложен повторно.
  if (
    cur &&
    typeof cur === 'object' &&
    cur.body !== undefined &&
    !cur.update_id &&
    !cur.message &&
    !cur.callback_query &&
    !cur.channel_post &&
    !cur.edited_message
  ) {
    cur = parseMaybeJson(cur.body);
  }

  // Если Worker прислал envelope вида { payload: {...} }.
  if (
    cur &&
    typeof cur === 'object' &&
    cur.payload &&
    !cur.update_id &&
    !cur.message &&
    !cur.callback_query
  ) {
    cur = parseMaybeJson(cur.payload);
  }

  return cur && typeof cur === 'object' ? cur : {};
}

function lower(value) {
  return String(value || '').trim().toLowerCase();
}

function safeText(value) {
  return String(value || '').trim();
}

function safeId(chatId) {
  return `${chatId || 'nochat'}_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`;
}

const incoming = unwrapIncoming($json);
const u = incoming;

const cb = u.callback_query || {};
const isCallback = !!u.callback_query;

const msg =
  u.message ||
  u.edited_message ||
  u.channel_post ||
  cb.message ||
  {};

const chat = msg.chat || {};
const from = msg.from || cb.from || {};

const cbData = safeText(cb.data);
const callbackQueryId = cb.id || '';

const photo = Array.isArray(msg.photo) && msg.photo.length
  ? msg.photo[msg.photo.length - 1]
  : null;

const caption = safeText(msg.caption);
const text = safeText(msg.text || caption);

const TOPIC_CREATE = 'создать тему';
const TOPIC_CREATE2 = 'создай тему';

const ARTICLE_PREFIXES = [
  'напиши статью',
  'напиши пост',
  'сделай статью',
  'сделай пост',
  'создай статью',
  'создай пост'
];

const NOISE_PREFIX_RE = /^\s*(на\s+тему|о\s+|про\s+)/i;

function isSlashTopic(value) {
  const low = lower(value);
  return low === '/topic' || low.startsWith('/topic ');
}

function isAskTopic(value) {
  const low = lower(value);
  return low === '/topic' || low === TOPIC_CREATE || low === TOPIC_CREATE2;
}

function isTopicCommand(value) {
  const raw = safeText(value);
  const low = lower(raw);

  if (isSlashTopic(raw) && low.length > '/topic'.length) return true;
  if (low.startsWith(TOPIC_CREATE + ' ')) return true;
  if (low.startsWith(TOPIC_CREATE2 + ' ')) return true;

  return ARTICLE_PREFIXES.some(p => low === p || low.startsWith(p + ' '));
}

function extractTopic(value) {
  const raw = safeText(value);
  const low = lower(raw);

  if (low === '/topic') return '';

  if (low.startsWith('/topic ')) {
    return raw.slice('/topic'.length).trim();
  }

  for (const p of [TOPIC_CREATE, TOPIC_CREATE2]) {
    if (low.startsWith(p + ' ')) {
      return raw.slice(p.length).trim();
    }
  }

  for (const p of ARTICLE_PREFIXES) {
    if (low === p) return raw;

    if (low.startsWith(p + ' ')) {
      return raw
        .slice(p.length)
        .replace(NOISE_PREFIX_RE, '')
        .trim() || raw;
    }
  }

  return '';
}

let route = 'unsupported';
let action = '';
let aspect_ratio = '';
let session_id = '';
let task_id = '';
let idea_id = '';
let trend_idea_id = '';

if (isCallback) {
  const parts = cbData.split('|');
  action = parts[0] || '';

  if (action === 'new_topic') {
    route = 'ask_topic';
  } else if (action === 'rev') {
    route = 'revise_post_requested';
    idea_id = parts.slice(1).join('|') || '';
  } else if (action === 'ar') {
    route = 'aspect_selected';
    aspect_ratio = parts[1] || '1:1';
    session_id = parts[2] || '';
  } else if (action === 'idea') {
    route = 'idea_selected';
    idea_id = parts.slice(1).join('|') || '';
  } else if (action === 'appr') {
    route = 'post_approved';
    idea_id = parts.slice(1).join('|') || '';
  } else if (action === 'par') {
    route = 'post_aspect_selected';
    aspect_ratio = parts[1] || '16:9';
    idea_id = parts.slice(2).join('|') || '';
  } else if (action === 'redo') {
    route = 'redo_task';
    task_id = parts[1] || '';
  } else if (action === 'ok') {
    route = 'ok_task';
    task_id = parts[1] || '';
  } else if (action === 'okphoto') {
    route = 'ok_photo_task';
    task_id = parts[1] || '';
  } else if (action === 'ok_full') {
    route = 'ok_full_task';
    if (parts.length >= 3) {
      idea_id = parts[1] || '';
      task_id = parts.slice(2).join('|') || '';
    } else {
      task_id = parts[1] || '';
    }
  } else if (action === 'repeat') {
    route = 'repeat_from_channel';
    task_id = parts[1] || '';
  } else if (action === 'ztopic') {
    route = 'trend_topic_selected';
    trend_idea_id = parts.slice(1).join('|') || '';
  } else {
    route = 'unsupported_callback';
  }

} else if (lower(text) === '/start') {
  route = 'start';
} else if (isAskTopic(text)) {
  route = 'ask_topic';
} else if (isTopicCommand(text)) {
  route = 'topic_received';
} else if (photo && text) {
  route = 'photo_prompt_received';
} else if (photo && !text) {
  route = 'photo_without_prompt';
} else if (text) {
  route = 'text_prompt_received';
}

const topic = route === 'topic_received' ? extractTopic(text) : '';

return [{
  json: {
    route,
    action,
    callback_data: cbData,
    callback_query_id: callbackQueryId,

    chat_id: chat.id || '',
    chat_type: chat.type || '',
    message_id: msg.message_id || '',

    from_user_id: from.id || '',
    username: from.username || '',
    first_name: from.first_name || '',
    last_name: from.last_name || '',

    text,
    topic,
    has_photo: !!photo,
    telegram_file_id: photo?.file_id || '',
    caption,

    aspect_ratio,
    session_id,
    task_id,
    idea_id,
    trend_idea_id,

    root_id: safeId(chat.id),
    received_at: new Date().toISOString(),
    raw_update_id: u.update_id || '',

    raw_update: u
  }
}];

const topic = String(
  $json.topic_text ||
  $json.text ||
  $json.user_prompt ||
  $json.topic ||
  ''
).trim();

function clean(value) {
  return String(value || '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
    .replace(/\bСРМ\b/gi, 'журнал заявок')
    .replace(/\bцрм\b/gi, 'журнал заявок')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

const topicClean = clean(topic);

const system_prompt = `
Ты русскоязычный маркетинговый стратег и редактор контент-завода TBC.

TBC — экосистема для предпринимателей Москвы:
1. бизнес-аудит магазинов, салонов, сервисов и торговых компаний;
2. AI-агенты, Telegram-боты, n8n, автоматизация заявок, записи, первичных консультаций и работы менеджеров;
3. TBC Academy — практическое обучение предпринимателей и сотрудников;
4. TBC Business Club — мастермайнды, бизнес-игры, встречи, выезды, разборы кейсов и нетворкинг.

ЦА: собственники и руководители малого/среднего бизнеса Москвы: магазины, салоны, клиники, мебельная розница, локальные услуги, B2B/B2C предприниматели.

Твоя задача:
- создать ровно 5 идей для будущего Telegram-поста / статьи;
- сделать идеи практичными, коммерчески полезными и не общими;
- выбрать самую сильную идею как selected_idea_no;
- не писать финальный пост;
- не писать image prompt.

Стиль:
- деловой, живой, конкретный;
- без воды, хайпа, эмодзи, хэштегов, markdown;
- без фраз “AI помогает бизнесу”, “повышает эффективность”, “цифровая трансформация”, “современные технологии”;
- показывай управленческий конфликт: где теряются заявки, деньги, время, запись, контроль, маржа или управляемость;
- не используй термин CRM/СРМ. Вместо этого: журнал заявок, таблица заявок, календарь записи, Telegram-бот, AI-агент, менеджерская панель, учет входящих обращений.

Верни только валидный JSON. Без markdown-обертки и пояснений.
`.trim();

const user_prompt = `
Тема пользователя:
${topicClean}

Сделай 5 идей.

Требования:
- если тема узкая, все 5 идей должны раскрывать её с разных бизнес-углов;
- если тема широкая, можно распределить идеи по направлениям TBC: AI-агенты, бизнес-аудит, обучение, бизнес-клуб;
- первые 2 идеи должны быть самыми коммерчески сильными;
- идеи не должны дублировать друг друга;
- каждая идея должна вести к одному из продуктов TBC: бизнес-аудит, AI-агент, Telegram-бот, автоматизация записи, обучение, консультация, бизнес-клуб.

Верни JSON строго такой структуры:

{
  "topic_text": "",
  "selected_idea_no": 1,
  "ideas": [
    {
      "idea_no": 1,
      "idea_title": "",
      "idea_description": "",
      "market_reason": "",
      "business_relevance": "",
      "content_angle": "",
      "owner_pain": "",
      "sales_hook": "",
      "practical_solution": "",
      "tbc_offer_path": "",
      "priority": 1
    }
  ]
}

Ограничения:
- ideas: ровно 5 объектов;
- idea_title: до 120 символов;
- idea_description: 1-2 предложения;
- market_reason: почему тема актуальна для рынка;
- business_relevance: как это влияет на деньги, заявки, запись, контроль или нагрузку менеджеров;
- content_angle: как подать материал практически;
- owner_pain: конкретная боль собственника;
- sales_hook: цепляющая фраза для Telegram;
- practical_solution: что можно сделать в бизнесе;
- tbc_offer_path: какой продукт TBC логично предложить;
- priority: 1, 2 или 3.
`.trim();

const responseSchema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    topic_text: { type: 'string' },
    selected_idea_no: { type: 'integer' },
    ideas: {
      type: 'array',
      minItems: 5,
      maxItems: 5,
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          idea_no: { type: 'integer' },
          idea_title: { type: 'string' },
          idea_description: { type: 'string' },
          market_reason: { type: 'string' },
          business_relevance: { type: 'string' },
          content_angle: { type: 'string' },
          owner_pain: { type: 'string' },
          sales_hook: { type: 'string' },
          practical_solution: { type: 'string' },
          tbc_offer_path: { type: 'string' },
          priority: { type: 'integer' }
        },
        required: [
          'idea_no',
          'idea_title',
          'idea_description',
          'market_reason',
          'business_relevance',
          'content_angle',
          'owner_pain',
          'sales_hook',
          'practical_solution',
          'tbc_offer_path',
          'priority'
        ]
      }
    }
  },
  required: ['topic_text', 'selected_idea_no', 'ideas']
};

const kie_body_json = JSON.stringify({
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'tbc_ideas_output',
      strict: true,
      schema: responseSchema
    }
  },
  temperature: 0.25,
  messages: [
    { role: 'system', content: system_prompt },
    { role: 'user', content: user_prompt }
  ]
});

const openai_body_json = kie_body_json;

return [{
  json: {
    ...$json,
    topic_text: topicClean,
    system_prompt,
    user_prompt,
    kie_body_json,
    openai_body_json
  }
}];

