function get(path, obj = $json) {
  return path.split('.').reduce((a, k) => a?.[k], obj);
}

function normalizeContent(value) {
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(p => p?.text || p?.content || '').join('\n');
  if (value && typeof value === 'object') return JSON.stringify(value);
  return String(value || '');
}

function clean(value, max = 2000) {
  return String(value ?? '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
    .replace(/\bСРМ\b/gi, 'журнал заявок')
    .replace(/\bцрм\b/gi, 'журнал заявок')
    .replace(/[ \t]{2,}/g, ' ')
    .trim()
    .slice(0, max);
}

function stripFences(value) {
  return String(value || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function parseLoose(rawValue) {
  let raw = stripFences(normalizeContent(rawValue));

  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) raw = raw.slice(first, last + 1);

  const variants = [
    raw,
    raw.replace(/[“”]/g, '"').replace(/,\s*}/g, '}').replace(/,\s*]/g, ']')
  ];

  for (const v of variants) {
    try {
      return {
        parsed: JSON.parse(v),
        parse_status: v === raw ? 'strict_json' : 'repaired_json',
        raw_preview: raw.slice(0, 1000)
      };
    } catch (e) {}
  }

  throw new Error('Gemini returned non-JSON ideas: ' + raw.slice(0, 700));
}

function toInt(value, fallback = 1) {
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : fallback;
}

const content =
  get('choices.0.message.content') ||
  get('choices.0.text') ||
  $json.content ||
  '{}';

const { parsed, parse_status, raw_preview } = parseLoose(content);

const current = (() => {
  try {
    return $('E01 Set Current Topic Row').first().json || {};
  } catch (e) {
    return {};
  }
})();

const a0 = (() => {
  try {
    return $('A02 Normalize Telegram Input').first().json || {};
  } catch (e) {
    return {};
  }
})();

const topicId =
  current.topic_id ||
  current.root_id ||
  a0.root_id ||
  a0.message_id ||
  '';

const topicText = clean(
  parsed.topic_text ||
  current.topic_text ||
  a0.topic ||
  a0.text ||
  ''
);

const selectedNo = toInt(parsed.selected_idea_no, 1);
const now = new Date().toISOString();

let ideas = Array.isArray(parsed.ideas) ? parsed.ideas.slice(0, 5) : [];

if (ideas.length < 5) {
  throw new Error(`Gemini response must contain exactly 5 ideas, got ${ideas.length}`);
}

ideas = ideas.map((idea, index) => ({
  idea_no: toInt(idea.idea_no, index + 1),
  idea_title: clean(idea.idea_title || idea.topic_text || `Идея ${index + 1}`, 160),
  idea_description: clean(idea.idea_description || idea.short_description || '', 500),
  market_reason: clean(idea.market_reason || '', 500),
  business_relevance: clean(idea.business_relevance || '', 500),
  content_angle: clean(idea.content_angle || '', 500),
  owner_pain: clean(idea.owner_pain || '', 300),
  sales_hook: clean(idea.sales_hook || '', 300),
  practical_solution: clean(idea.practical_solution || '', 400),
  tbc_offer_path: clean(idea.tbc_offer_path || '', 400),
  priority: toInt(idea.priority, index + 1)
}));

return ideas.map((idea) => {
  const ideaNo = idea.idea_no;
  const baseId = topicId || current.chat_id || a0.chat_id || 'topic';

  return {
    json: {
      idea_id: `${baseId}_${ideaNo}_${Date.now()}`,
      topic_id: topicId,
      topic_text: topicText,

      idea_no: ideaNo,
      idea_title: idea.idea_title,
      idea_description: idea.idea_description,
      market_reason: idea.market_reason,

      business_relevance: idea.business_relevance,
      content_angle: idea.content_angle,
      owner_pain: idea.owner_pain,
      sales_hook: idea.sales_hook,
      practical_solution: idea.practical_solution,
      tbc_offer_path: idea.tbc_offer_path,
      priority: idea.priority,

      selected_idea_no: selectedNo,
      is_selected: 'FALSE',

      final_post_text_ru: '',
      image_prompt_en: '',

      chat_id: current.chat_id || a0.chat_id || '',
      username: current.username || a0.username || '',
      root_id: current.root_id || a0.root_id || '',

      created_at: now,
      selected_at: '',
      idea_status: 'draft',
      post_status: 'idea_only',
      post_approved_at: '',
      image_requested_at: '',

      full_article_text_ru: '',
      full_article_status: 'not_started',
      full_article_created_at: '',
      full_article_target_platforms: 'joomla_site,vc.ru,dzen,tenchat',

      source_trend_idea_id: current.source_trend_idea_id || '',
      source_competitor_post_ids: current.source_competitor_post_ids || '',

      llm_model_used: $json.model || 'gemini-2.5-flash',
llm_parse_status: parse_status,
usage_prompt_tokens: $json.usage?.prompt_tokens || '',
usage_completion_tokens: $json.usage?.completion_tokens || '',
usage_total_tokens: $json.usage?.total_tokens || '',
kie_credits_consumed: $json.credits_consumed || ''
    }
  };
});

const src = $json || {};

function firstJson(name) {
  try {
    return $(name).first().json;
  } catch (e) {
    return null;
  }
}

const ctx =
  firstJson('H02 Build KIE Payload From Approved Post') ||
  firstJson('T7 Build Single Image Payload') ||
  firstJson('I11 Build KIE Payload From Session') ||
  firstJson('L02 Build Redo Payload Same Prompt') ||
  {};

const taskId =
  src.data?.taskId ||
  src.data?.task_id ||
  src.taskId ||
  src.task_id ||
  src.data?.id ||
  src.id ||
  src.result?.taskId ||
  src.result?.task_id ||
  src.result?.id ||
  '';

const isAuthError =
  Number(src.code || src.statusCode || src.status || 0) === 401 ||
  String(src.msg || src.message || '').toLowerCase().includes('unauthorized') ||
  String(src.error || '').toLowerCase().includes('unauthorized');

if (isAuthError) {
  throw new Error(
    'KIE authorization failed. Проверь H03 Header Auth credential: Authorization: Bearer <KIE_API_KEY>. Ответ KIE: ' +
    JSON.stringify(src).slice(0, 1200)
  );
}

if (!taskId) {
  throw new Error(
    'KIE не вернул task_id. Задача изображения не создана. Ответ KIE: ' +
    JSON.stringify(src).slice(0, 1200)
  );
}

const now = new Date().toISOString();

return [{
  json: {
    task_id: String(taskId),
    idea_id: ctx.idea_id || '',
    root_id: ctx.root_id || ctx.topic_id || '',
    session_id: ctx.session_id || '',
    chat_id: ctx.chat_id || '',
    username: ctx.username || '',
    topic_text: ctx.topic_text || '',
    mode: ctx.mode || 'text_to_image',
    frame_role: ctx.frame_role || 'single_post_image',
    prompt_text: ctx.prompt_text || ctx.image_prompt_en || '',
    final_post_text_ru: ctx.final_post_text_ru || '',
    model: ctx.model || 'gpt-image-2-text-to-image',
    aspect_ratio: ctx.aspect_ratio || '16:9',
    resolution: ctx.resolution || '1K',
    n: Number(ctx.n || 1),
    watermark: Boolean(ctx.watermark || false),
    seed: Number(ctx.seed || 1),
    source_image_url: ctx.source_image_url || '',
    status: 'created',
    post_status: 'image_task_requested',
    image_requested_at: now,
    retry_count: Number(ctx.retry_count || 0),
    original_task_id: ctx.original_task_id || '',
    created_at: ctx.created_at || now,
    callback_at: '',
    completed_at: '',
    sent_at: '',
    result_url: '',
    drive_result_id: '',
    error_message: '',
    user_send_status: '',
    channel_publish_status: '',
    user_sent_at: '',
    channel_published_at: ''
  }
}];

const ctx = $('A02 Normalize Telegram Input').first().json || {};
const row = $json;
const sid = row.session_id || ctx.session_id || '';
const chatId = row.chat_id || ctx.chat_id || '';
const t = '\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u0441\u043e\u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u0435 \u0441\u0442\u043e\u0440\u043e\u043d \u0434\u043b\u044f Wan 2.7 Image:';
