  if (text.length <= maxLen) return text;

  const cut = text.slice(0, maxLen);
  const end = Math.max(
    cut.lastIndexOf('. '),
    cut.lastIndexOf('; '),
    cut.lastIndexOf(', '),
    cut.lastIndexOf(' ')
  );

  return (end > 1200 ? cut.slice(0, end + 1) : cut).trim();
}

