function extractJsonObject(raw) {
  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) return raw.slice(first, last + 1);
  return raw;
}

function parseJson(raw) {
  const variants = [
    raw,
    extractJsonObject(raw),
    extractJsonObject(raw)
      .replace(/[“”]/g, '"')
      .replace(/[‘’]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']')
  ];

  for (const v of variants) {
    try {
      return JSON.parse(v);
    } catch (e) {}
  }

  throw new Error('Mini post model returned non-JSON content: ' + raw.slice(0, 700));
}

function cleanTelegramText(value) {
  return String(value || '')
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
