    .replace(/\b([1-9])\?\?/g, '$1.')
    .replace(/\?\?/g, '')
    .replace(/ /g, '')
    .replace(/\uFFFD/g, '')
    .replace(/\r/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
