  if (typeof content === 'string') return content.trim();
  if (content && typeof content === 'object') return JSON.stringify(content);
  return '';
}

function parseMaybeJson(value) {
  const raw = String(value || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  if (!raw) return null;

  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === 'object' ? parsed : null;
  } catch (e) {
    const first = raw.indexOf('{');
    const last = raw.lastIndexOf('}');
    if (first >= 0 && last > first) {
      try {
        return JSON.parse(raw.slice(first, last + 1));
      } catch (e2) {}
    }
  }

  return null;
}

function safeArray(value) {
  if (Array.isArray(value)) return value.map(v => compact(v, 120)).filter(Boolean);
  if (typeof value === 'string') {
    return value
      .split(/[,;\n]/g)
      .map(v => compact(v, 120))
      .filter(Boolean);
  }
  return [];
}

function firstSentences(value, count = 4, maxLen = 1200) {
  const text = compact(value, maxLen + 500);
  const parts = text.match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [];
  return compact(parts.slice(0, count).join(' '), maxLen);
}

