function cutNice(value, max = 3900) {
  const text = cleanText(value);
  if (text.length <= max) return text;

  const cut = text.slice(0, max);
  const lastBreak = cut.lastIndexOf('\n\n');
  if (lastBreak > Math.floor(max * 0.65)) return cut.slice(0, lastBreak).trim();

  const lastDot = Math.max(
    cut.lastIndexOf('.'),
    cut.lastIndexOf('!'),
    cut.lastIndexOf('?')
  );

  if (lastDot > Math.floor(max * 0.65)) return cut.slice(0, lastDot + 1).trim();

  const lastSpace = cut.lastIndexOf(' ');
  return cut.slice(0, lastSpace > 0 ? lastSpace : max).trim();
}
