const tz = 'Europe/Moscow';

function normalize(value) {
  return String(value ?? '').trim();
}

function ymdInTz(date) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).formatToParts(date);

  const map = Object.fromEntries(parts.map(p => [p.type, p.value]));
  return `${map.year}-${map.month}-${map.day}`;
}

function parseDate(value) {
  const raw = normalize(value);
  if (!raw) return null;

  const parsed = new Date(raw);
  if (!Number.isNaN(parsed.getTime())) return parsed;

  const m = raw.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (m) {
    const d = new Date(`${m[1]}-${m[2]}-${m[3]}T12:00:00+03:00`);
    return Number.isNaN(d.getTime()) ? null : d;
  }

  return null;
}

function rowDate(row, fieldNames) {
  for (const name of fieldNames) {
    const d = parseDate(row[name]);
    if (d) return ymdInTz(d);
  }
  return '';
}

function rowTime(row, fieldNames) {
  for (const name of fieldNames) {
    const d = parseDate(row[name]);
    if (d) return d.getTime();
  }
  return 0;
}

function isActive(row) {
  const flag = normalize(row.is_active).toLowerCase();
  if (!flag) return true;
  return ['true', '1', 'yes', 'y', 'da', 'active', 'on'].includes(flag);
}

function isProcessed(row) {
  return Boolean(normalize(row.processed_at));
}

function hasUsefulContent(row) {
  return [
    row.title,
    row.raw_text,
    row.short_summary,
    row.topic_candidate,
    row.business_relevance,
    row.content_angle
  ].some(v => normalize(v).length >= 12);
}

function score(row) {
  const p = Number(row.priority || 5);
  return Number.isFinite(p) ? p : 5;
}

function recency(row) {
  return rowTime(row, ['published_at', 'source_published_at', 'collected_at', 'created_at', 'updated_at']);
}

function sortRows(a, b) {
  return score(a) - score(b) || recency(b) - recency(a);
}

function daysOld(row) {
  const t = recency(row);
  if (!t) return 9999;
  return Math.floor((Date.now() - t) / (24 * 60 * 60 * 1000));
}

function take(list, mode, targetDate, sourcePeriod, max = 40) {
  const selected = list
    .filter(isActive)
    .filter(hasUsefulContent)
    .sort(sortRows)
    .slice(0, max);

  return selected.map(row => ({
    json: {
      ...row,
      target_trend_date: targetDate,
      source_period: sourcePeriod,
      c03_selection_mode: mode,
      c03_selected_count: selected.length,
      c03_total_rows: rows.length
    }
  }));
}

