    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/(^|[\s.,;:!?()[\]{}«»"“”'`+\-–—\/\\])(max|мах)(?=$|[\s.,;:!?()[\]{}«»"“”'`+\-–—\/\\])/gi, '$1')
    .trim();

  if (Number.isFinite(max) && max > 0 && s.length > max) {
    s = s.slice(0, max).trim();
  }

  return s;
}

function one(v, max = 500) {
  return clean(v, max)
    .replace(/\n+/g, ' ')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

function toArray(v) {
  if (Array.isArray(v)) return v.map(x => clean(x, 2000)).filter(Boolean);

  if (typeof v === 'string') {
    const raw = clean(v, 10000);

    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) return parsed.map(x => clean(x, 2000)).filter(Boolean);
    } catch (e) {}

    return raw
      .split('\n')
      .map(x => x.replace(/^\d+[\).\s-]+/, '').trim())
      .filter(Boolean);
  }

  return [];
}

function num(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function ymdCompact(dateStr) {
  const raw = String(dateStr || '').trim();
  const m = raw.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (m) return `${m[1]}${m[2]}${m[3]}`;

  const d = new Date(raw || Date.now());
  if (!Number.isNaN(d.getTime())) {
    const y = d.getFullYear();
    const mo = String(d.getMonth() + 1).padStart(2, '0');
    const da = String(d.getDate()).padStart(2, '0');
    return `${y}${mo}${da}`;
  }

  return 'unknown_date';
}

function extractContent(j) {
  if (typeof j === 'string') return j;

  const candidates = [
    j?.choices?.[0]?.message?.content,
    j?.data?.choices?.[0]?.message?.content,
    j?.response?.choices?.[0]?.message?.content,
    j?.message?.content,
    j?.output_text,
    j?.content?.[0]?.text,
    j?.data?.content?.[0]?.text,
    j?.result?.content,
    j?.result,
    j?.text
  ];

  for (const c of candidates) {
    if (typeof c === 'string' && c.trim()) return c;

    if (Array.isArray(c)) {
      const joined = c
        .map(x => typeof x === 'string' ? x : (x?.text || x?.content || ''))
        .filter(Boolean)
        .join('\n');

      if (joined.trim()) return joined;
    }
  }

  return JSON.stringify(j);
}

function stripCodeFences(s) {
  return String(s || '')
    .replace(/^\s*```json\s*/i, '')
    .replace(/^\s*```\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

function parseModelJson(rawText) {
  const raw = stripCodeFences(rawText);

  try {
    return {
      parsed: JSON.parse(raw),
      parse_status: 'strict_json'
    };
  } catch (e1) {
    const start = raw.indexOf('{');
    const end = raw.lastIndexOf('}');

    if (start >= 0 && end > start) {
      let candidate = raw.slice(start, end + 1)
        .replace(/,\s*([}\]])/g, '$1')
        .replace(/[\u0000-\u001F]+/g, match => {
          if (match === '\n' || match === '\t') return match;
          return ' ';
        });

      try {
        return {
          parsed: JSON.parse(candidate),
          parse_status: 'repaired_json'
        };
      } catch (e2) {
        throw new Error(
          'C06: cannot parse model JSON after repair. Preview: ' +
          raw.slice(0, 1200)
        );
      }
    }

    throw new Error(
      'C06: model response does not contain JSON object. Preview: ' +
      raw.slice(0, 1200)
    );
  }
}

function normalizeOwnerBriefText(v) {
