function clean(v, max = 900) {
  let s = String(v ?? '');

  s = s
    .replace(/<[^>]*>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#8230;/g, '…')
    .replace(/[{}\[\]*`~|]/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();

  if (Number.isFinite(max) && max > 0 && s.length > max) {
    s = s.slice(0, max).trim();
  }

  return s;
}

function one(v, max = 500) {
  return clean(v, max)
    .replace(/\n+/g, ' ')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

function short(v, max = 48) {
  const s = one(v, 200);
  return s.length > max ? s.slice(0, max - 1).trim() + '…' : s;
}

function trimNice(value, max = 3900) {
  const text = clean(value, 10000);
  if (text.length <= max) return text;

  const slice = text.slice(0, max);
  const points = [
    slice.lastIndexOf('\n\n'),
    slice.lastIndexOf('. '),
    slice.lastIndexOf('! '),
    slice.lastIndexOf('? '),
    slice.lastIndexOf('\n'),
    slice.lastIndexOf('; '),
    slice.lastIndexOf(', '),
    slice.lastIndexOf(' ')
  ];

  const cut = points.find(p => p > Math.floor(max * 0.72));
  const base = cut > 0 ? slice.slice(0, cut + 1) : slice;

  return base
    .trim()
    .replace(/[.,;:!?-]+$/u, '')
    .trim() + '…';
}

