}

function mergeNonEmpty(base, extra) {
  const out = { ...(base || {}) };

  for (const [k, v] of Object.entries(extra || {})) {
    if (v === null || v === undefined) continue;
    if (typeof v === 'string' && !v.trim()) continue;
    if (Array.isArray(v) && !v.length) continue;
