function parseFeed(text, src) {
  const xml = String(text || '');
  const posts = [];

  const rssItems = getBlocks(xml, 'item');
  for (const block of rssItems) {
    posts.push({
      title: getTag(block, 'title'),
      url: getTag(block, 'link') || getTag(block, 'guid'),
      summary: getTag(block, 'description') || getTag(block, 'content:encoded'),
      published_at: getTag(block, 'pubDate') || getTag(block, 'dc:date')
    });
  }

  if (!posts.length) {
    const atomEntries = getBlocks(xml, 'entry');
    for (const block of atomEntries) {
      posts.push({
        title: getTag(block, 'title'),
        url: getAtomLink(block) || getTag(block, 'id'),
        summary: getTag(block, 'summary') || getTag(block, 'content'),
        published_at: getTag(block, 'updated') || getTag(block, 'published')
      });
    }
  }

  if (!posts.length) {
    const sitemapUrls = getBlocks(xml, 'url');
    for (const block of sitemapUrls) {
      posts.push({
        title: getTag(block, 'loc').split('/').filter(Boolean).pop() || getTag(block, 'loc'),
        url: getTag(block, 'loc'),
        summary: '',
        published_at: getTag(block, 'lastmod')
      });
    }
  }

  if (!posts.length) {
    const re = /<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
    let m;
    while ((m = re.exec(xml)) !== null && posts.length < MAX_PER_SOURCE) {
      const href = absoluteUrl(m[1], src.source_url);
      const title = clean(m[2], 240);

      if (!href || href.startsWith('mailto:') || href.startsWith('tel:')) continue;
      if (!title || title.length < 8) continue;

      posts.push({
        title,
        url: href,
        summary: title,
        published_at: ''
      });
    }
  }

  const seen = new Set();

  return posts
    .map((p, idx) => buildPost(src, p, idx))
    .filter(p => {
      const key = p.post_url || p.title;
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, MAX_PER_SOURCE);
}

