function clean(value) {
  return String(value ?? '')
    .replace(/\r/g, '')
    .replace(/[ \t]+$/gm, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function truncateText(value, max = 4000) {
  const text = clean(value);
  if (text.length <= max) return text;

  const slice = text.slice(0, max);
  const cutPoints = [
    slice.lastIndexOf('\n\n'),
    slice.lastIndexOf('. '),
    slice.lastIndexOf('! '),
    slice.lastIndexOf('? '),
    slice.lastIndexOf('\n'),
    slice.lastIndexOf(' ')
  ];

  const cut = cutPoints.find(p => p > Math.floor(max * 0.7));
  return (cut > 0 ? slice.slice(0, cut + 1) : slice).trim() + '…';
}

function safeText(value) {
  return clean(value)
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
    .replace(/\bСРМ\b/gi, 'журнал заявок')
    .replace(/\bцрм\b/gi, 'журнал заявок')
    .replace(/\bMAX\b/gi, '')
    .replace(/\bMax\b/g, '')
    .replace(/\bМАХ\b/g, '')
    .replace(/офлайн бизнес Москва/gi, 'офлайн-бизнес в Москве')
    .trim();
}

function flat(value) {
  return safeText(value).replace(/\s+/g, ' ').trim();
}

function firstNonEmpty(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function splitKeywords(value) {
  if (Array.isArray(value)) return value.map(flat).filter(Boolean);

  return String(value || '')
    .replace(/\r/g, '\n')
    .replace(/https?:\/\/\S+/gi, ' ')
    .replace(/[;|]+/g, ',')
    .split(/,|\n/)
    .map(flat)
    .filter(v => v.length >= 3 && v.length <= 80);
}

function uniq(values) {
  const seen = new Set();
  const out = [];

  for (const value of values) {
    const v = flat(value);
    if (!v) continue;

    const key = v.toLowerCase().replace(/ё/g, 'е');
    if (seen.has(key)) continue;

    seen.add(key);
    out.push(v);
  }

  return out;
}

// Важно: synonymNormalize используется только для скоринга релевантности SEO-ключей.
// Она не меняет итоговые ключи, не меняет статью и не подменяет текст в выдаче модели.
function synonymNormalize(value) {
  return flat(value)
    .toLowerCase()
    .replace(/ё/g, 'е')
    .replace(/\bai\b/g, 'ии')
    .replace(/\bискусственный интеллект\b/g, 'ии')
    .replace(/\bчат[- ]?бот\b/g, 'бот')
    .replace(/\btelegram\b/g, 'телеграм')
    .replace(/\bтелеграм[- ]?бот\b/g, 'бот')
    .replace(/\bзаявки\b/g, 'обращения')
    .replace(/\bзаявка\b/g, 'обращение')
    .replace(/\bзапись\b/g, 'бронирование')
    .replace(/\bзаписи\b/g, 'бронирование')
    .replace(/\bаудит\b/g, 'диагностика')
    .replace(/\bагент\b/g, 'ассистент')
    .replace(/\bагенты\b/g, 'ассистенты');
}

function words(value) {
  const stop2 = new Set(['я', 'и', 'в', 'с', 'к', 'у', 'а', 'о', 'на', 'по', 'за', 'из', 'от', 'до']);
  const allowShort = new Set(['ии', 'ai']);

  return synonymNormalize(value)
    .split(/[^a-zа-я0-9]+/gi)
    .map(v => v.trim())
    .filter(Boolean)
    .filter(v => v.length >= 3 || allowShort.has(v))
    .filter(v => !stop2.has(v));
}

function keywordScore(keyword, sourceText) {
  const kw = synonymNormalize(keyword);
  const src = synonymNormalize(sourceText);
  const srcWords = new Set(words(sourceText));
  const kwWords = words(keyword);

  let score = src.includes(kw) ? 12 : 0;

  for (const w of kwWords) {
    if (srcWords.has(w)) score += 2;
  }

  const coverage = kwWords.length
    ? kwWords.filter(w => srcWords.has(w)).length / kwWords.length
    : 0;

  score += Math.round(coverage * 6);

  if (/москва|москов/i.test(keyword)) score += 1;
  if (/бизнес|продаж|заявк|обращен|запис|агент|бот|telegram|телеграм|аудит|магазин|салон|сервис|календар/i.test(keyword)) score += 1;

  if (kwWords.length > 5) score -= 1;

  return score;
}

function selectKeywords(bank, sourceText, maxCount = 20) {
  const prepared = uniq(bank)
    .map(k => safeText(k).replace(/офлайн бизнес Москва/gi, 'офлайн-бизнес в Москве'))
    .filter(k => !/мастермайнд|обучение GPT|курсы по искусственному интеллекту/i.test(k));

  const scored = prepared
    .map(keyword => ({ keyword, score: keywordScore(keyword, sourceText) }))
    .sort((a, b) => b.score - a.score || a.keyword.length - b.keyword.length);

  const relevant = scored.filter(x => x.score > 0).map(x => x.keyword);

  const fallback = prepared.filter(k =>
    /бизнес|продаж|заявк|обращен|запис|агент|ассистент|бот|telegram|телеграм|ии|ai|москва|аудит|диагностик|салон|магазин|сервис|календар/i.test(k)
  );

  return uniq([...relevant, ...fallback]).slice(0, maxCount);
}

