function clean(value) {
  return String(value || '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+$/gm, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function hasForbiddenTerms(value) {
  const s = String(value || '');
  return /\bCRM\b|\bC\.R\.M\.\b|Customer Relationship Management|\bСРМ\b|\bцрм\b|\bMAX\b|\bMax\b|\bМАХ\b/i.test(s);
}

function removeForbiddenTerms(value) {
  return clean(value)
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
    .replace(/\bСРМ\b/gi, 'журнал заявок')
    .replace(/\bцрм\b/gi, 'журнал заявок')
    .replace(/\bMAX\b/gi, '')
    .replace(/\bMax\b/g, '')
    .replace(/\bМАХ\b/g, '')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

function stripLeadingH1Duplicate(text, title) {
  let s = clean(text);
  const titleClean = clean(title).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  s = s.replace(/^H1\s*:\s*[^\n]+\n+/i, '');

  if (titleClean) {
    const re = new RegExp('^' + titleClean + '\\s*\\n+', 'i');
    s = s.replace(re, '');
  }

  return clean(s);
}

function normalizeArticleText(value, title) {
  let s = removeForbiddenTerms(value);

  s = s
    .replace(/\*\*(РАЗДЕЛ\s+\d+[\.\:]\s*[^\n*]+)\*\*/gim, '$1')
    .replace(/^#{1,6}\s*(РАЗДЕЛ\s+\d+[\.\:]\s*[^\n]+)/gim, '$1')
    .replace(/^#{1,6}\s*/gm, '')
    .replace(/[ \t]+$/gm, '');

  // Если модель поставила РАЗДЕЛ внутри строки, переносим его на новую строку.
  s = s.replace(/([^\n])\s+(РАЗДЕЛ\s+\d+[\.\:]\s+)/gi, '$1\n\n$2');

  // Нормализуем двоеточие после номера раздела.
  s = s.replace(/^(РАЗДЕЛ\s+\d+)\s*[:：]\s*/gim, '$1. ');

  // Убираем дублирующий H1 из тела, если модель его всё же вставила.
  s = stripLeadingH1Duplicate(s, title);

  return clean(s);
}

function stripHtml(value) {
  return removeForbiddenTerms(value)
    .replace(/<[^>]+>/g, ' ')
    .replace(/[#*_>`]/g, '')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function limitText(value, max) {
  const text = stripHtml(value);
  if (text.length <= max) return text;

  const cut = text.slice(0, max + 1);
  const lastSpace = cut.lastIndexOf(' ');
  const end = lastSpace > Math.floor(max * 0.7) ? lastSpace : max;

  return text.slice(0, end).replace(/[,.!?:;\-]+$/g, '').trim();
}

function toArray(value) {
  if (Array.isArray(value)) return value.map(v => stripHtml(v)).filter(Boolean);

  if (typeof value === 'string') {
    return value
      .split(/[,;|\n]\s*/g)
      .map(v => stripHtml(v))
      .filter(Boolean);
  }

  return [];
}

function uniq(values) {
  const seen = new Set();
  const out = [];

  for (const value of values) {
    const v = stripHtml(value);
    const key = v.toLowerCase().replace(/ё/g, 'е').trim();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(v);
  }

  return out;
}

function getSectionNumbers(text) {
  const matches = [...clean(text).matchAll(/^РАЗДЕЛ\s+(\d+)[\.\):\-]\s+/gim)];
  const nums = matches
    .map(m => Number(m[1]))
    .filter(n => Number.isFinite(n));

  return [...new Set(nums)].sort((a, b) => a - b);
}

function countHeadings(text) {
  return getSectionNumbers(text).length;
}

function firstWords(text, maxWords = 100) {
  return clean(text)
    .replace(/^РАЗДЕЛ\s+\d+[\.\):\-]\s+.*$/gim, '')
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, maxWords)
    .join(' ');
}

function containsText(haystack, needle) {
  const h = removeForbiddenTerms(haystack).toLowerCase().replace(/ё/g, 'е');
  const n = removeForbiddenTerms(needle).toLowerCase().replace(/ё/g, 'е').trim();
  return !!n && h.includes(n);
}

function keywordInLead(text, keyword) {
  return containsText(firstWords(text, 120), keyword);
}

function sentenceEndsOk(text) {
  const t = clean(text);
  return /[.!?…»)]$/.test(t.slice(-3));
}

function hasLists(text) {
  return /(^|\n)(\d+[\).\s-]+|[-—]\s+).{8,}/m.test(text);
