  function walk(value) {
    if (!value || typeof value !== 'object') return null;
    if (seen.has(value)) return null; seen.add(value);
    for (const [key, val] of Object.entries(value)) {
      if (keys.includes(String(key))) { const n = Number(val); if (Number.isFinite(n) && n > 0) return n; }
    }
    for (const val of Object.values(value)) { const found = walk(val); if (found) return found; }
    return null;
  }
  return walk(obj);
}
