function cleanText(value) {
  return String(value || '')
    .replace(/\r/g, '')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+$/gm, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function escapeJsonForScript(obj) {
  return JSON.stringify(obj)
    .replace(/</g, '\\u003C')
    .replace(/>/g, '\\u003E')
    .replace(/&/g, '\\u0026');
}

function stripHtml(value) {
  return String(value || '').replace(/<[^>]*>/g, '').trim();
}

function stripInlineMarkdown(value) {
  return String(value || '')
    .trim()
    .replace(/^(\*\*|__)(.+)\1$/s, '$2')
    .trim();
}

function translitRu(value) {
  const map = {
    а:'a', б:'b', в:'v', г:'g', д:'d', е:'e', ё:'e', ж:'zh', з:'z', и:'i', й:'y',
    к:'k', л:'l', м:'m', н:'n', о:'o', п:'p', р:'r', с:'s', т:'t', у:'u', ф:'f',
    х:'h', ц:'c', ч:'ch', ш:'sh', щ:'sch', ъ:'', ы:'y', ь:'', э:'e', ю:'yu', я:'ya'
  };

  return String(value || '')
    .toLowerCase()
    .split('')
    .map(ch => map[ch] ?? ch)
    .join('');
}

function normalizeAlias(value) {
  return translitRu(value)
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-')
    .slice(0, 120)
    .replace(/-+$/g, '') || 'article';
}

function stripTechnicalSuffix(alias) {
  return String(alias || '')
    .replace(/-(?:[a-f0-9]{8}|[a-f0-9]{12}|[a-f0-9]{16}|[a-f0-9]{24}|[a-f0-9]{32})$/i, '')
    .replace(/-+$/g, '');
}

function makeAlias(title) {
