function splitSentencesRu(text) {
  const normalized = String(text || '').replace(/\s+/g, ' ').trim();
  if (!normalized) return [];

  const matches = normalized.match(/[^.!?…]+[.!?…]+(?:["»”])?|[^.!?…]+$/g) || [];
  return matches.map(s => s.trim()).filter(Boolean);
}

function chooseReadmoreSentenceCount(sentences) {
  if (!sentences.length) return 0;
  if (sentences.length <= 3) return sentences.length;

  let count = 3;
  let lead = sentences.slice(0, count).join(' ');

  while (count < 5 && count < sentences.length && lead.length < 420) {
    count += 1;
    lead = sentences.slice(0, count).join(' ');
  }

  return count;
}

function isSectionHeadingText(text) {
  return /^РАЗДЕЛ\s+\d+\s*[\.\-:—]?\s*/i.test(text);
}

function sectionTitle(text) {
  return String(text || '')
    .replace(/^РАЗДЕЛ\s+\d+\s*[\.\-:—]?\s*/i, '')
    .trim();
}

function parseMarkdownHeading(line) {
  const m = String(line || '').trim().match(/^(#{1,6})\s+(.+)$/);
  if (!m) return null;

  return {
    level: m[1].length,
    text: stripInlineMarkdown(m[2])
  };
}

function isNumberedItem(text) {
  return /^\d+\s*[\.\)]\s+/.test(String(text || '').trim());
}

function numberedItemText(text) {
  return String(text || '').trim().replace(/^\d+\s*[\.\)]\s+/, '').trim();
}

function isBulletItem(text) {
  return /^[-–—*]\s+/.test(String(text || '').trim());
}

function bulletItemText(text) {
  return String(text || '').trim().replace(/^[-–—*]\s+/, '').trim();
}

function isNestedListIndent(rawLine) {
  return /^\s{2,}(?:[-–—*]|\d+\s*[\.\)])\s+/.test(String(rawLine || ''));
}

function isFaqQuestion(text) {
  return /^Вопрос:\s*/i.test(String(text || '').trim());
}

function isFaqAnswer(text) {
  return /^Ответ:\s*/i.test(String(text || '').trim());
}

function faqQuestionText(text) {
  return String(text || '').trim().replace(/^Вопрос:\s*/i, '').trim();
}

function faqAnswerText(text) {
  return String(text || '').trim().replace(/^Ответ:\s*/i, '').trim();
}

function closeList(state, html) {
  if (state.list === 'ol') html.push('</ol>');
  if (state.list === 'ul') html.push('</ul>');
  state.list = '';
}

function pushParagraph(html, state, text) {
  const t = String(text || '').trim();
  if (!t) return;

  closeList(state, html);
  html.push(`<p>${escapeHtml(t)}</p>`);
}

function warnPendingFaqIfNeeded(ctx, nextType) {
  if (!ctx.pendingFaq) return;

  warn(
    'FAQ_QUESTION_WITHOUT_ANSWER',
    'FAQ-вопрос без последующего ответа. Вопрос выведен как h3, но в FAQ Schema.org не добавлен.',
    {
      question: ctx.pendingFaq.question,
      next_type: nextType
    }
  );

  ctx.pendingFaq = null;
}

function structuralTextFromLine(line) {
  const heading = parseMarkdownHeading(line);
  return stripInlineMarkdown(heading ? heading.text : line);
}

function isMajorHeadingBlock(block) {
  const firstLine = String(block || '')
    .split('\n')
    .map(x => x.trim())
    .find(Boolean) || '';

  if (!firstLine) return false;

  const heading = parseMarkdownHeading(firstLine);
  const text = structuralTextFromLine(firstLine);

  if (isSectionHeadingText(text)) return true;

  if (heading && !isNumberedItem(text) && !isBulletItem(text)) {
    return true;
  }

  return false;
}

function processLine(rawLine, html, state, ctx) {
  if (!String(rawLine || '').trim()) return;

  if (isNestedListIndent(rawLine)) {
    warn(
      'NESTED_LIST_INDENT_DETECTED',
      'Обнаружен вложенный список или отступ списка. Вложенность не строится, строка обработана как обычный пункт текущего списка.',
      { line: String(rawLine).trim().slice(0, 180) }
    );
  }

  const originalLine = String(rawLine || '').replace(/\t/g, '  ').replace(/\s+$/g, '');
  const line = originalLine.trim();
  if (!line) return;

  const heading = parseMarkdownHeading(line);
  const text = structuralTextFromLine(line);

  const markdownListHeading =
    heading && (isNumberedItem(text) || isBulletItem(text));

  if (markdownListHeading) {
    warn(
      'MARKDOWN_LIST_HEADING_NORMALIZED',
      'Строка вида ## 1. ... или ## - ... преобразована в пункт списка, а не в h2.',
      { line: line.slice(0, 180) }
    );
  }

  if (isFaqQuestion(text)) {
    if (ctx.pendingFaq) {
      warnPendingFaqIfNeeded(ctx, 'new_faq_question');
    }

    closeList(state, html);

    const q = faqQuestionText(text);
    if (q) {
      ctx.pendingFaq = { question: q };
      html.push(`<h3>${escapeHtml(q)}</h3>`);
    }
    return;
  }

  if (isFaqAnswer(text)) {
    closeList(state, html);

    const a = faqAnswerText(text);

    if (ctx.pendingFaq && ctx.pendingFaq.question && a) {
      ctx.faqItems.push({
        question: ctx.pendingFaq.question,
        answer: a
      });
      ctx.pendingFaq = null;
    } else {
      warn(
        'FAQ_ANSWER_WITHOUT_QUESTION',
        'Найден FAQ-ответ без предыдущего FAQ-вопроса. Ответ выведен как обычный абзац.',
        { answer: a.slice(0, 180) }
      );
    }

    if (a) html.push(`<p>${escapeHtml(a)}</p>`);
    return;
  }

  if (isSectionHeadingText(text)) {
    warnPendingFaqIfNeeded(ctx, 'section_heading');
    closeList(state, html);

    const h = sectionTitle(text);
    if (h) html.push(`<h2>${escapeHtml(h)}</h2>`);
    return;
  }

  if (heading && !markdownListHeading) {
    warnPendingFaqIfNeeded(ctx, 'markdown_heading');
    closeList(state, html);

    const tag = heading.level >= 3 ? 'h3' : 'h2';
    if (text) html.push(`<${tag}>${escapeHtml(text)}</${tag}>`);
    return;
  }

  if (isNumberedItem(text)) {
    warnPendingFaqIfNeeded(ctx, 'numbered_list');

    if (state.list !== 'ol') {
      closeList(state, html);
      html.push('<ol>');
      state.list = 'ol';
    }

    html.push(`<li>${escapeHtml(numberedItemText(text))}</li>`);
    return;
  }

  if (isBulletItem(text)) {
    warnPendingFaqIfNeeded(ctx, 'bullet_list');

    if (state.list !== 'ul') {
      closeList(state, html);
      html.push('<ul>');
      state.list = 'ul';
    }

    html.push(`<li>${escapeHtml(bulletItemText(text))}</li>`);
    return;
  }

  warnPendingFaqIfNeeded(ctx, 'paragraph');
  pushParagraph(html, state, text);
}

function appendFaqSchema(html, faqItems) {
  if (!faqItems.length) return;

  const schema = {
    '@context': 'https://schema.org',
    '@type': 'FAQPage',
    mainEntity: faqItems.slice(0, 6).map(item => ({
      '@type': 'Question',
      name: item.question,
      acceptedAnswer: {
        '@type': 'Answer',
        text: item.answer
      }
    }))
  };

  html.push(`<script type="application/ld+json">${escapeJsonForScript(schema)}</script>`);
}

function buildArticleHtml(rawText, title) {
  let text = cleanText(rawText);

  const lines = text.split('\n');
  const firstLineClean = stripHtml(
    String(lines[0] || '')
      .replace(/^#{1,6}\s+/, '')
      .trim()
  );

  if (lines.length && firstLineClean === stripHtml(title).trim()) {
    text = cleanText(lines.slice(1).join('\n'));
  }

  const blocks = text
    .split(/\n\s*\n/)
    .map(b => cleanText(b))
    .filter(Boolean);

  const firstSectionIndex = blocks.findIndex(block => isMajorHeadingBlock(block));
  const introEndIndex = firstSectionIndex >= 0 ? firstSectionIndex : Math.min(blocks.length, 2);

  const introRaw = blocks.slice(0, introEndIndex).join(' ');
  const restBlocks = blocks.slice(introEndIndex);

  const introSentences = splitSentencesRu(introRaw);
  const leadCount = chooseReadmoreSentenceCount(introSentences);

  const introLead = introSentences.slice(0, leadCount).join(' ');
  const introRemainder = introSentences.slice(leadCount).join(' ');

  const html = [];
  const state = { list: '' };
  const ctx = {
    pendingFaq: null,
    faqItems: []
  };

  if (introLead) {
    html.push(`<p>${escapeHtml(introLead)}</p>`);
    html.push('<hr id="system-readmore" />');
  }

  if (introRemainder) {
    pushParagraph(html, state, introRemainder);
  }

  for (const block of restBlocks) {
    const rawLines = block
      .split('\n')
      .filter(line => String(line || '').trim());

    if (!rawLines.length) continue;

    const hasStructuralLines = rawLines.some(line => {
      const textLine = structuralTextFromLine(line.trim());
      const heading = parseMarkdownHeading(line.trim());

      return Boolean(
        heading ||
        isSectionHeadingText(textLine) ||
        isNumberedItem(textLine) ||
        isBulletItem(textLine) ||
        isFaqQuestion(textLine) ||
        isFaqAnswer(textLine)
      );
    });

    if (!hasStructuralLines && rawLines.length > 1) {
      processLine(rawLines.map(x => x.trim()).join(' '), html, state, ctx);
      continue;
    }

    for (const rawLine of rawLines) {
      processLine(rawLine, html, state, ctx);
    }
  }

  closeList(state, html);
  warnPendingFaqIfNeeded(ctx, 'end_of_article');

  if (!html.some(x => x.includes('system-readmore')) && html.length > 1) {
    html.splice(1, 0, '<hr id="system-readmore" />');
    warn(
      'READMORE_FALLBACK_USED',
      'Read More вставлен резервно после первого HTML-блока, потому что вводный блок не был определен стандартно.'
    );
  }

  appendFaqSchema(html, ctx.faqItems);

  return {
    html: html.join('\n'),
    faqItems: ctx.faqItems
  };
}

