    .replace(/\bMAX\b/gi, '')
    .replace(/\bMax\b/g, '')
    .replace(/\bМАХ\b/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, max);
}

function cutSentence(value, max = 650) {
  const text = clean(value, max + 200);
  if (text.length <= max) return text;

  const cut = text.slice(0, max);
  const lastDot = Math.max(
    cut.lastIndexOf('.'),
    cut.lastIndexOf('!'),
    cut.lastIndexOf('?')
  );

  if (lastDot > Math.floor(max * 0.55)) {
    return cut.slice(0, lastDot + 1).trim();
  }

  const lastSpace = cut.lastIndexOf(' ');
  return cut.slice(0, lastSpace > 0 ? lastSpace : max).trim() + '...';
}

