  }
}];

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

const prep = getNodeJson('F15 Build VK Long Announcement Payload') || getNodeJson('F12 Prepare Full Article Payload');
const joomla = getNodeJson('F14 Joomla Publish Article');
const vk = getNodeJson('F16 VK Long wall.post');

const now = new Date().toISOString();

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function safeString(value) {
  return String(value || '').trim();
}

function clean(value, max = 20000) {
  return String(value || '')
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
    .replace(/\bСРМ\b/gi, 'журнал заявок')
    .replace(/\bцрм\b/gi, 'журнал заявок')
    .replace(/\bMAX\b/gi, '')
    .replace(/\bMax\b/g, '')
    .replace(/\bМАХ\b/g, '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
    .slice(0, max);
}

function getJoomlaArticleObject(response) {
  if (response?.data && !Array.isArray(response.data)) return response.data;
  if (Array.isArray(response?.data) && response.data.length > 0) return response.data[0];
  return response || {};
}

function extractJoomlaId(response, fallback = {}) {
  const article = getJoomlaArticleObject(response);

  return safeString(pick(
    response?.data?.id,
    response?.data?.attributes?.id,
    response?.id,
    response?.article_id,
    article?.id,
    article?.attributes?.id,
    fallback?.site_article_id,
    prep?.site_article_id
  ));
}

function extractJoomlaAlias(response, fallback = {}) {
  const article = getJoomlaArticleObject(response);

  return safeString(pick(
    response?.data?.attributes?.alias,
    response?.alias,
    article?.attributes?.alias,
    fallback?.site_article_alias,
    fallback?.article_alias,
    fallback?.alias,
    fallback?.site_article_payload?.alias,
    prep?.site_article_alias,
    prep?.article_alias,
    prep?.alias,
    prep?.site_article_payload?.alias
  ));
}

function hasArticleIdInUrl(url) {
  return /\/blog\/\d+-/i.test(String(url || ''));
}

function extractDirectJoomlaUrl(response, fallback = {}) {
  const article = getJoomlaArticleObject(response);

  return safeString(pick(
    response?.site_article_url,
    response?.url,
    response?.data?.url,
    response?.data?.attributes?.url,
    response?.data?.attributes?.link,
    article?.attributes?.url,
    article?.attributes?.link,
    fallback?.site_article_url,
    fallback?.site_article_url_expected,
    prep?.site_article_url,
    prep?.site_article_url_expected
  ));
}

function buildCanonicalJoomlaUrl(response, fallback = {}) {
  const id = extractJoomlaId(response, fallback);
  const alias = extractJoomlaAlias(response, fallback);

  // Главное правило: если есть id + alias, всегда строим canonical Joomla URL.
  if (id && alias) {
    return `https://tb-academy.ru/blog/${id}-${alias}`;
  }

  const direct = extractDirectJoomlaUrl(response, fallback);

  // Готовый URL используем только если он уже содержит Joomla ID.
  if (direct && hasArticleIdInUrl(direct)) {
    return direct;
  }

  if (alias) {
    return `https://tb-academy.ru/blog/${alias}`;
  }

  return direct || '';
}

function extractVkPostId(response) {
  return safeString(pick(
    response?.response?.post_id,
    response?.post_id,
    response?.data?.response?.post_id,
    response?.data?.post_id
  ));
}

function extractVkError(response) {
  return safeString(pick(
    response?.error?.error_msg,
    response?.error?.message,
    response?.message,
    response?.description,
    response?.data?.error?.error_msg,
    response?.data?.error?.message
  ));
}

const siteArticleId = extractJoomlaId(joomla, prep);
const siteArticleAlias = extractJoomlaAlias(joomla, prep);
const siteArticleUrl = buildCanonicalJoomlaUrl(joomla, prep);

const vkPostId = extractVkPostId(vk);
const vkError = extractVkError(vk);

const sitePublishedOk = !!siteArticleUrl || !!siteArticleId;
const vkBranchExecuted = Object.keys(vk || {}).length > 0;
const vkPublishedOk = !!vkPostId && !vkError;

const fullPublishStatus = sitePublishedOk
  ? (vkBranchExecuted && vkError ? 'partial_published' : 'published')
  : 'failed';

const fullPublishedChannels = [
  sitePublishedOk ? 'site' : '',
  vkPublishedOk ? 'vk_long' : ''
].filter(Boolean).join(',');

const lastPublishError = [
  sitePublishedOk ? '' : 'Joomla article was not published',
  vkBranchExecuted ? vkError : ''
].filter(Boolean).join(' | ');

return [{
  json: {
    ...prep,

    task_id: safeString(prep.task_id),
    idea_id: safeString(prep.idea_id),
    topic_id: safeString(prep.topic_id),

    full_publish_status: fullPublishStatus,
    full_published_channels: fullPublishedChannels,
    last_publish_error: lastPublishError,

    site_publish_status: sitePublishedOk ? 'published' : 'failed',
    site_published_at: sitePublishedOk ? now : '',
    site_article_id: siteArticleId,
    site_article_alias: siteArticleAlias,
    site_article_url: siteArticleUrl,

    site_image_url: safeString(prep.site_image_url),
    site_image_filename: safeString(prep.site_image_filename),

    logo_applied_status: safeString(prep.logo_applied_status || 'applied'),
    logo_applied_at: safeString(prep.logo_applied_at || now),

    ftp_upload_status: safeString(prep.ftp_upload_status || 'uploaded'),
    ftp_uploaded_at: safeString(prep.ftp_uploaded_at || now),

    vk_long_status: vkBranchExecuted
      ? (vkPublishedOk ? 'published' : (vkError ? 'failed' : 'not_published'))
      : '',
    vk_long_post_id: vkPostId,
    vk_long_published_at: vkPublishedOk ? now : '',
    vk_long_error: vkError,
    vk_long_url: safeString(prep.vk_long_url),
    vk_long_message: clean(prep.vk_long_message, 6000),
    vk_long_text_length: safeString(prep.vk_long_text_length),

    article_title: clean(prep.full_article_title_ru || prep.article_title || prep.title, 300),
    full_article_title_ru: clean(prep.full_article_title_ru || prep.article_title || prep.title, 300),
    full_article_text_ru: clean(prep.full_article_text_ru, 30000),
    article_html: clean(prep.article_html, 50000),

    site_meta_description: safeString(prep.site_meta_description),
    site_meta_keywords: safeString(prep.site_meta_keywords),

    blogger_status: safeString(prep.blogger_status),
    blogger_published_at: safeString(prep.blogger_published_at),
    blogger_post_id: safeString(prep.blogger_post_id),
    blogger_post_url: safeString(prep.blogger_post_url),
    blogger_error: safeString(prep.blogger_error),

    full_status_updated_at: now
  },
  binary: $input.first().binary || {}
}];

const imageTask = $('F03 Lookup image_tasks by task_id').first().json || {};
const entry = $('F01 FULL Callback Entry Router').first().json || {};

function normalize(value) {
  return String(value ?? '')
    .replace(/\s+/g, ' ')
    .trim();
}

function hasText(value) {
  return normalize(value).length > 20;
}

const rows = $input.all().map(item => item.json || {});

const targetIdeaId = normalize(
  entry.idea_id ||
  imageTask.idea_id ||
  imageTask.post_idea_id ||
  imageTask.source_idea_id
);

const targetTaskId = normalize(entry.task_id || imageTask.task_id);

if (!targetTaskId) {
  throw new Error('F02A: missing task_id from Full callback / image_tasks');
}

if (!targetIdeaId) {
  throw new Error('F02A: missing idea_id. Full publish must use ok_full|idea_id|task_id');
}

const selected = rows.find(row => normalize(row.idea_id) === targetIdeaId);

if (!selected) {
  throw new Error('F02A: no post_ideas row found by idea_id=' + targetIdeaId);
}

if (!hasText(selected.full_article_text_ru)) {
  throw new Error('F02A: selected idea has no full_article_text_ru. idea_id=' + targetIdeaId);
}

return [{
  json: {
    ...selected,
    task_id: targetTaskId,
    selected_by_idea_id: targetIdeaId,
    selected_from_image_task_id: imageTask.task_id || ''
  }
}];

