const prep = $('F12 Prepare Full Article Payload').first().json || {};
const upload = $input.first().json || {};
const now = new Date().toISOString();
if (!prep.site_article_payload) {
  throw new Error('F13A: Missing site_article_payload from F12 Prepare Full Article Payload');
}
if (!prep.site_image_path || !prep.site_image_url || !prep.site_image_ftp_path) {
