}

const postId = safeString(response.id || response.post_id || '');
const postUrl = safeString(response.url || response.selfLink || '');
const status = postId ? (ctx.blogger_is_draft ? 'draft_created' : 'published') : 'failed';

const siteArticleUrl = safeString(ctx.site_article_url || '');

if (!siteArticleUrl) {
  throw new Error('B02A: missing ctx.site_article_url from B01');
}

if (!hasArticleIdInUrl(siteArticleUrl)) {
  throw new Error('B02A: site_article_url has no Joomla article ID: ' + siteArticleUrl);
}

return [{
  json: {
    ...ctx,

    site_article_url: siteArticleUrl,
    site_article_id: safeString(ctx.site_article_id),
    site_article_alias: safeString(ctx.site_article_alias),
    site_image_url: safeString(ctx.site_image_url),

    article_title: safeString(ctx.full_article_title_ru || ctx.article_title || ctx.blogger_title),
    full_article_title_ru: safeString(ctx.full_article_title_ru || ctx.article_title || ctx.blogger_title),

    blogger_response: response,
    blogger_status: status,
    blogger_published_at: safeString(response.published || response.updated || now),
    blogger_post_id: postId,
    blogger_post_url: postUrl,
    blogger_title: safeString(ctx.blogger_title || ctx.full_article_title_ru || ctx.article_title),
    blogger_error: postId ? '' : JSON.stringify(response).slice(0, 1000),
    blogger_merged_at: now
  }
}];

const current = $input.first().json || {};

function getNodeJson(name) {
  try {
    return $(name).first().json || {};
  } catch (e) {
    return {};
  }
}

const f12 = getNodeJson('F12 Prepare Full Article Payload');
const f14 = getNodeJson('F14 Joomla Publish Article');

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function compact(value) {
  return String(value || '')
    .replace(/\s+/g, ' ')
    .trim();
}

function clean(value) {
  return String(value || '')
    .replace(/\r/g, '')
    .replace(/\bCRM\b/gi, 'журнал заявок')
    .replace(/\bC\.R\.M\.\b/gi, 'журнал заявок')
    .replace(/\bCustomer Relationship Management\b/gi, 'журнал заявок')
    .replace(/\bСРМ\b/gi, 'журнал заявок')
    .replace(/\bцрм\b/gi, 'журнал заявок')
    .replace(/\bMAX\b/gi, '')
    .replace(/\bMax\b/g, '')
    .replace(/\bМАХ\b/g, '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function escapeHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function escapeHtmlAttr(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function safeUrl(value) {
  const url = compact(value);
  if (!/^https?:\/\//i.test(url)) return '';
  return url;
}

function getArticleObj(response) {
  if (response?.data && !Array.isArray(response.data)) return response.data;
  if (Array.isArray(response?.data) && response.data.length) return response.data[0];
  return response || {};
}

function getArticleId(response, fallback) {
  const article = getArticleObj(response);

  return String(pick(
    response?.data?.id,
    response?.data?.attributes?.id,
    response?.id,
    response?.article_id,
    article?.id,
    article?.attributes?.id,
    fallback?.site_article_id
  )).trim();
}

function getArticleAlias(response, fallback) {
  const article = getArticleObj(response);

  return compact(pick(
    response?.data?.attributes?.alias,
    response?.alias,
    article?.attributes?.alias,
    fallback?.article_alias,
    fallback?.alias,
    fallback?.site_article_payload?.alias
  )).slice(0, 240);
}

function getArticleTitle(response, fallbackA, fallbackB) {
  const article = getArticleObj(response);

  return compact(pick(
    fallbackA?.full_article_title_ru,
    fallbackA?.article_title,
    fallbackB?.full_article_title_ru,
    fallbackB?.article_title,
    response?.data?.attributes?.title,
    article?.attributes?.title,
    fallbackA?.title,
    fallbackB?.title,
    fallbackB?.site_article_payload?.title,
    'Статья TBC Academy'
  )).slice(0, 160);
}

function hasArticleIdInUrl(url) {
  return /\/blog\/\d+-/i.test(String(url || ''));
}

function buildJoomlaArticleUrl(response, currentRow, prepRow) {
  const id = getArticleId(response, currentRow) || getArticleId(response, prepRow);
  const alias = getArticleAlias(response, currentRow) || getArticleAlias(response, prepRow);

  if (id && alias) {
    return `https://tb-academy.ru/blog/${id}-${alias}`;
  }

  const existing = safeUrl(pick(
    currentRow?.site_article_url,
    response?.site_article_url,
    response?.data?.attributes?.url,
    response?.data?.attributes?.link,
    prepRow?.site_article_url,
    prepRow?.site_article_url_expected
  ));

  if (existing && hasArticleIdInUrl(existing)) {
    return existing;
  }

  if (alias) {
    return `https://tb-academy.ru/blog/${alias}`;
  }

  return existing || 'https://tb-academy.ru/blog';
}

function stripDangerousHtml(html) {
  return String(html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<hr\s+id=["']system-readmore["']\s*\/?>/gi, '')
    .replace(/<[^>]+id=["']system-readmore["'][^>]*>/gi, '')
    .replace(/<figure[\s\S]*?<\/figure>/gi, '')
    .replace(/<img[^>]*>/gi, '')
    .replace(/\s(class|style|id|loading|width|height|srcset|sizes)=["'][^"']*["']/gi, '')
    .trim();
}

function plainTextFromHtml(value) {
  return String(value || '')
    .replace(/<h[1-6][^>]*>/gi, '\n\n')
    .replace(/<\/h[1-6]>/gi, ':\n\n')
    .replace(/<p[^>]*>/gi, '\n\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<li[^>]*>/gi, '\n- ')
    .replace(/<\/li>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();
}

function splitSentences(text) {
  return compact(text).match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [];
}

function insertSectionBreaks(text) {
  let result = clean(text);

  // Поддержка наших новых разделов "РАЗДЕЛ 1. ..."
  result = result.replace(/\s*(РАЗДЕЛ\s+\d+\.\s+[^\n.?!]{6,140})\s*/gi, '\n\n$1\n\n');

  const headings = [
    'Рынок и проблема',
    'Рыночная проблема',
    'Проблема рынка',
    'Почему это важно сейчас',
    'Почему это важно',
    'Практическое решение',
    'Как это работает',
    'Архитектура и интеграция',
    'Техническая реализация',
    'Пример внедрения',
    'Кейс внедрения',
    'Метрики до и после',
    'Метрики до/после',
    'Какие метрики отслеживать',
    'Риски и как их снизить',
    'Типичные ошибки',
    'Первые действия для владельца',
    'Что сделать первым',
    'План внедрения',
    'Бизнес-вывод',
    'Мягкий следующий шаг',
    'Вывод'
  ];

  for (const heading of headings) {
    const escaped = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const re = new RegExp(`\\s*(${escaped})\\s*[:：]\\s*`, 'gi');
    result = result.replace(re, '\n\n$1:\n\n');
  }

  return clean(result);
}

function textToBloggerHtml(text) {
  let raw = insertSectionBreaks(text);

  let blocks = raw
    .split(/\n\s*\n/g)
    .map(v => v.trim())
    .filter(Boolean);

  if (blocks.length < 4) {
    const sentences = splitSentences(raw).map(v => v.trim()).filter(Boolean);
    blocks = [];

    for (let i = 0; i < sentences.length; i += 3) {
      blocks.push(sentences.slice(i, i + 3).join(' '));
    }
  }

  const html = [];

  for (const block of blocks) {
    const line = block.trim();
    if (!line) continue;

    const isRazdelHeading = /^РАЗДЕЛ\s+\d+\.\s+/i.test(line) && line.length <= 180;

    const isColonHeading =
      line.length >= 4 &&
      line.length <= 120 &&
      /[:：]$/.test(line) &&
      !/[.!?]$/.test(line.replace(/[:：]$/, ''));

    if (isRazdelHeading) {
      html.push('<h2>' + escapeHtml(line) + '</h2>');
    } else if (isColonHeading) {
      html.push('<h2>' + escapeHtml(line.replace(/[:：]$/, '')) + '</h2>');
    } else if (/^\-\s+/.test(line)) {
      const items = line
        .split(/\n+/)
        .map(v => v.replace(/^\-\s+/, '').trim())
        .filter(Boolean);

      html.push('<ul>');
      for (const item of items) {
        html.push('<li>' + escapeHtml(item) + '</li>');
      }
      html.push('</ul>');
    } else {
      html.push('<p>' + escapeHtml(line).replace(/\n/g, '<br>') + '</p>');
    }
  }

  return html.join('\n');
}

if (current.site_publish_status !== 'published') {
  throw new Error('B01 Blogger: Joomla article is not published. Stop Blogger branch.');
}

const siteArticleUrl = buildJoomlaArticleUrl(f14, current, f12);

if (!safeUrl(siteArticleUrl)) {
  throw new Error('B01 Blogger: missing valid Joomla site_article_url. Stop Blogger branch.');
}

const siteImageUrl = safeUrl(
  current.site_image_url ||
  f12.site_image_url ||
  ''
);

if (!siteImageUrl) {
  throw new Error('B01 Blogger: missing site_image_url. Stop Blogger branch.');
}

// Важно: Blogger title = H1 Joomla, а НЕ seo_title.
const title = getArticleTitle(f14, current, f12);

const fullText = clean(
  current.full_article_text_ru ||
  f12.full_article_text_ru ||
  current.final_post_text_ru ||
  f12.final_post_text_ru ||
  ''
);

const joomlaHtml = stripDangerousHtml(
  current.article_html ||
  f12.article_html ||
  f12.site_article_payload?.articletext ||
  ''
);

let articleHtml = '';

if (fullText) {
  articleHtml = textToBloggerHtml(fullText);
} else if (joomlaHtml) {
  articleHtml = textToBloggerHtml(plainTextFromHtml(joomlaHtml));
} else {
  throw new Error('B01 Blogger: no article text found');
}

const sourceBlock =
  `<p><em>Оригинал статьи опубликован на <a href="${escapeHtmlAttr(siteArticleUrl)}">TBC Academy</a>.</em></p>`;

const imageBlock =
  `<p><img src="${escapeHtmlAttr(siteImageUrl)}" alt="${escapeHtmlAttr(title)}" style="max-width:100%;height:auto;" /></p>`;

const finalLinkBlock =
  `<hr><p><strong>Полная версия и материалы:</strong> <a href="${escapeHtmlAttr(siteArticleUrl)}">читать на TBC Academy</a></p>`;

const bloggerContentHtml = [
  sourceBlock,
  imageBlock,
  articleHtml,
  finalLinkBlock
].filter(Boolean).join('\n\n');

const bloggerBody = {
  title,
  content: bloggerContentHtml
};

// Боевой режим: false.
// Для тестового черновика временно поменять на true.
const bloggerIsDraft = false;

return [{
  json: {
    ...f12,
    ...current,

    site_article_url: siteArticleUrl,
    site_image_url: siteImageUrl,

    article_title: title,
    full_article_title_ru: current.full_article_title_ru || f12.full_article_title_ru || title,

    blogger_title: title,
    blogger_content_html: bloggerContentHtml,
    blogger_body: bloggerBody,
    blogger_body_json: JSON.stringify(bloggerBody),
    blogger_is_draft: bloggerIsDraft,

    blogger_canonical_fixed_at: new Date().toISOString()
  }
}];

