={{ (() => {
  const j = $json || {};

  function clean(v) {
    return String(v ?? '')
      .replace(/<[^>]*>/g, '')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&quot;/g, '"')
      .replace(/[{}\[\]*`~|]/g, ' ')
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      .replace(/[ \t]+\n/g, '\n')
      .replace(/\n[ \t]+/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .replace(/[ \t]{2,}/g, ' ')
      .trim();
  }

  function parseJsonObj(v) {
    try {
      return typeof v === 'string' ? JSON.parse(v) : (v || {});
    } catch (e) {
      return {};
    }
  }

  function list(v) {
    const raw = clean(v);
    if (!raw) return [];

    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) return parsed.map(x => clean(x)).filter(Boolean);
    } catch (e) {}

    return raw
      .split('\n')
      .map(x => x.replace(/^\d+[\).\s-]+/, '').trim())
      .filter(Boolean);
  }

  function finishSentence(v) {
    const s = clean(v);
    if (!s) return '';

    if (/[.!?…)]$/u.test(s)) return s;

    const points = [
      s.lastIndexOf('. '),
      s.lastIndexOf('! '),
      s.lastIndexOf('? '),
      s.lastIndexOf('\n\n')
    ];

    const cut = points.find(p => p > Math.floor(s.length * 0.65));
    return cut > 0 ? s.slice(0, cut + 1).trim() : s;
  }

  function trimNice(v, max = 3900) {
    const text = clean(v);
    if (text.length <= max) return finishSentence(text);

    const slice = text.slice(0, max);
    const points = [
      slice.lastIndexOf('\n\n'),
      slice.lastIndexOf('. '),
      slice.lastIndexOf('! '),
      slice.lastIndexOf('? '),
      slice.lastIndexOf('\n'),
      slice.lastIndexOf('; '),
      slice.lastIndexOf(', '),
      slice.lastIndexOf(' ')
    ];

    const cut = points.find(p => p > Math.floor(max * 0.72));
    return finishSentence(cut > 0 ? slice.slice(0, cut + 1) : slice);
  }

  function beautify(v) {
    let s = clean(v);

    // Убираем хвостовые дубли, потому что ниже они выводятся отдельными блоками.
    s = s.split(/\n\s*(Почему это важно:|Рыночные сигналы:|Что сделать собственнику:|Что может предложить TBC:|Почему сейчас:|Риски:)/i)[0];

    s = s
      .replace(/^Бриф дня для собственника\s*/i, '')
      .replace(/[ \t]*(Сигнал дня:)/g, '\n\n📍 $1\n')
      .replace(/[ \t]*(Аналитическая сводка:)/g, '\n\n📊 $1\n')
      .replace(/[ \t]*(Вывод:)/g, '\n\n🧾 $1\n')
      .replace(/[ \t]*(Что сделать в ближайшие 7 дней:)/g, '\n\n✅ $1\n')
      .replace(/[ \t]*(Как это связано с TBC:)/g, '\n\n🔗 $1\n')
      .replace(/[ \t]*(\d+\.\s*Фактор:)/g, '\n\n$1')
      .replace(/[ \t]*(Что это значит для собственника:)/g, '\nЧто это значит для собственника:')
      .replace(/[ \t]*(Где риск денег\/времени\/заявок:)/g, '\nГде риск денег/времени/заявок:')
      .replace(/[ \t]*(Что проверить:)/g, '\nЧто проверить:')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

    return s;
  }

  function numberedBlock(title, rows, maxRows = 5) {
    const arr = rows.slice(0, maxRows);
    if (!arr.length) return '';

    const body = arr
      .map((x, i) => `${i + 1}. ${clean(x)}`)
      .join('\n\n');

    return `${title}\n${body}`;
  }

  const strategic = parseJsonObj(j.strategic_conclusion_json);

  const main = trimNice(beautify(j.owner_brief_text || ''), 2500);

  const marketSignals = list(j.owner_key_signals);
  const actions = list(j.owner_recommended_actions);
  const risks = list(j.owner_risk_notes);

  const blocks = [];

  blocks.push('📌 Бриф дня для собственника');

  if (j.trend_title) {
    blocks.push(`🧭 Тренд:\n${clean(j.trend_title)}`);
  }

  if (main) {
    blocks.push(main);
  } else {
    blocks.push(`📍 Сигнал дня:\n${clean(j.trend_summary || '')}`);
    blocks.push(`💼 Почему это важно:\n${clean(j.business_relevance || '')}`);
  }

  const actionsBlock = numberedBlock('✅ Что сделать в ближайшие 7 дней:', actions, 3);
  if (actionsBlock) blocks.push(actionsBlock);

  const signalsBlock = numberedBlock('📡 Рыночные сигналы:', marketSignals, 3);
  if (signalsBlock) blocks.push(signalsBlock);

  const risksBlock = numberedBlock('⚠️ Риски:', risks, 2);
  if (risksBlock) blocks.push(risksBlock);

  const tbc = clean(strategic.what_tbc_can_offer || '');
  if (tbc) {
    blocks.push(`🔗 Что может предложить TBC:\n${tbc}`);
  }

  return trimNice(
    blocks
      .map(clean)
      .filter(Boolean)
      .join('\n\n')
      .replace(/\n{3,}/g, '\n\n'),
    3900
  );
})() }}

