const item = $input.first() || {};
const j = item.json || {};
const binary = item.binary || {};

function s(value) {
  return String(value ?? '').trim();
}

function cleanText(value) {
  return s(value)
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/\s+/g, ' ')
    .trim();
}

function firstNonEmpty(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && s(v) !== '') return v;
  }
  return '';
}

function isPublishedStatus(value) {
  return ['published', 'created', 'done', 'success'].includes(s(value).toLowerCase());
}

const payload = j.site_article_payload || {};

const title = firstNonEmpty(
  payload.title,
  j.article_title,
  j.full_article_title_ru,
  j.title
);

const alias = firstNonEmpty(
  payload.alias,
  j.article_alias,
  j.alias
);

const articleText = firstNonEmpty(
  payload.articletext,
  j.article_html,
  j.full_article_text_ru
);

const existingArticleId = s(firstNonEmpty(
  j.site_article_id,
  payload.id
));

const existingArticleUrl = s(j.site_article_url);
const sitePublishStatus = s(j.site_publish_status);

const textLen = cleanText(articleText).length;
const warnings = [];

let joomla_action = 'create';
let joomla_block_reason = '';
let joomla_decision_reason = 'Ручное решение на публикацию принято. Joomla payload готов.';

if (existingArticleId || existingArticleUrl || isPublishedStatus(sitePublishStatus)) {
  joomla_action = 'skip';
  joomla_decision_reason = 'Статья уже имеет признаки публикации: site_article_id / site_article_url / site_publish_status.';
}

else if (!payload || typeof payload !== 'object' || Object.keys(payload).length === 0) {
  joomla_action = 'block';
  joomla_block_reason = 'Нет site_article_payload для Joomla.';
}

else if (!s(title)) {
  joomla_action = 'block';
  joomla_block_reason = 'Нет заголовка статьи.';
}

else if (!s(alias)) {
  joomla_action = 'block';
  joomla_block_reason = 'Нет alias статьи.';
}

else if (textLen < 1000) {
  joomla_action = 'block';
  joomla_block_reason = `Текст статьи слишком короткий для публикации: ${textLen} символов.`;
}

else if (!payload.catid) {
  joomla_action = 'block';
  joomla_block_reason = 'Нет catid Joomla-категории.';
}

else {
  const seoPassed = s(j.seo_passed).toLowerCase();

  if (seoPassed === 'review' || seoPassed === 'false') {
    warnings.push('SEO/QC требует ручной проверки, но публикация разрешена после ручного нажатия “Опубликовать FULL”.');
  }

  const seoLen = Number(j.seo_length_chars || textLen || 0);
  if (seoLen > 0 && seoLen < 6500) {
    warnings.push(`Длина статьи ниже целевой: ${seoLen} символов.`);
  }

  const imagePath = firstNonEmpty(
    j.site_image_path,
    j.site_image_url,
    payload.images?.image_intro,
    payload.images?.image_fulltext
  );

  if (!s(imagePath)) {
    warnings.push('Не найден путь к изображению статьи.');
  }
}

return [{
  json: {
    ...j,

    site_article_payload: {
      ...payload,
      title: payload.title || title,
      alias: payload.alias || alias,
      articletext: payload.articletext || articleText
    },

    title,
    alias,
    article_title: title,
    article_alias: alias,
    article_html: j.article_html || articleText,

    site_article_payload_ready: joomla_action !== 'block',

    joomla_action,
    joomla_block_reason,
    joomla_decision_reason,
    joomla_gate_warnings: warnings.join(' | '),
    joomla_decided_at: new Date().toISOString(),

    debug_f13b_text_len: textLen,
    debug_f13b_has_payload: Boolean(payload && Object.keys(payload).length),
    debug_f13b_title: title,
    debug_f13b_alias: alias
  },
  binary
}];

