={{ (() => {
  const j = $json || {};
  function clean(value, max = 1200) {
    return String(value ?? '')
      .replace(/<[^>]*>/g, '')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/\r/g, '')
      .replace(/\n{3,}/g, '\n\n')
      .trim()
      .slice(0, max);
  }
  const action = clean(j.joomla_action || 'unknown', 80);
  const reason = clean(j.joomla_block_reason || 'Причина не указана', 1200);
  const title = clean(j.full_article_title_ru || j.seo_title || j.idea_title || 'Без заголовка', 200);
  const seo = clean(j.seo_passed || '', 40);
  const qc = clean(j.qc_severity || '', 80);
  const len = clean(j.seo_length_chars || '', 40);
  const labelMap = {
    skip: 'Статья уже опубликована',
    block: 'Публикация заблокирована',
    review: 'Нужна ручная проверка',
    create: 'Разрешена публикация'
  };
  return [
    '⚠️ Joomla-публикация остановлена.',
    '',
    'Статус: ' + (labelMap[action] || action),
    '',
    'Заголовок:',
    title,
    '',
    len ? 'Длина: ' + len + ' знаков' : '',
    seo ? 'SEO passed: ' + seo : '',
    qc ? 'QC severity: ' + qc : '',
    '',
    'Причина:',
    reason,
    '',
    'Что делать:',
    action === 'skip'
      ? 'Повторный create не выполняем, чтобы не создать дубль статьи.'
      : action === 'review'
        ? 'Проверьте full_article_text_ru и SEO/QC в Google Sheets. Если всё устраивает, можно сделать ручной override позже.'
        : 'Нужно исправить статью или перегенерировать Full перед публикацией.'
  ].filter(Boolean).join('\n').slice(0, 3900);
})() }}
